import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import Image from './phonk_wallpaper.jpg';
import reportWebVitals from './reportWebVitals';
import Header from './header.js';
import Footer from './footer.js';
import MainPage from './main.js';

let flag = false

function LastNews() {
  return (
    <div>
      <p>{flag === true ? "Не наводися сюда" : "Тут вообще должна быть самая последняя новость, но так как я очень ленивый, здесь просто написана всякая фигня : )"}</p>
    </div>
  )
}

function MouseOver() {
  flag = true
  root.render(<App />)
}

function MouseOut() {
  flag = false
  root.render(<App />)
}

function App() {
  return(
  <div id="main_page">
    <Header />
    <MainPage />
    <Footer />
  </div>
  )
}


const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App />);

